export function checkerStrictParityLineText(file: string, line: number): string | undefined {
  return checkerStrictParitySourceLines.find((entry) => entry.file === file && entry.line === line)?.text;
}

export function checkerStrictParityFiles(): readonly string[] {
  return [...new Set(checkerStrictParitySourceLines.map((entry) => entry.file))].sort();
}
